class Solution:
   def swap(self, a, b):
      a, b = b, a

   def solve(self, nums: list[int]):
      for i in range(len(nums)):
         for j in range(i + 1, len(nums)):
            if nums[j] < nums[i]:
               self.swap(nums[i], nums[j])

      return nums

print(Solution().solve(list(map(int, input().split()))))
